<template>
  <div :class="`question-box-pdf is-show-${isParse}`">
    <div v-if="previewHtml" v-html="previewHtml"></div>
    <div v-else class="fail-text">数据获取失败</div>
  </div>
</template>

<script>
export default {
  name: "question",
  data() {
    return {
      previewHtml: ""
    };
  },
  props: ["questionCont", "isParse"],
  mounted() {
    this.renderQsDom();
  },
  watch: {
    questionCont() {
      this.renderQsDom();
    }
  },
  methods: {
    renderQsDom() {
      // console.log('this.questionCont', this.questionCont)
      let config = {
        analyzeVersion: 2,
        hideSource: true,
        hideDifficulty: true,
        excludeLogicToAutoLayout: [5],
        labels: {
          answer: "答案",
          analyze: "解析",
          queId: "ID",
        },
      };
      if (this.questionCont.source_type === 2 || this.questionCont.source_type === 3) {
        if (window.TalqsTemplate && window.TalqsTemplate.render && this.questionCont && this.questionCont.question_info) this.previewHtml = window.TalqsTemplate.render(this.questionCont.question_info, config);
      } else if (this.questionCont.source_type === 1) {
        if (this.isParse) {
          this.previewHtml = '<div style="padding-top:10px;text-align:left;font-size: 16px;">暂无答案</div>'
        } else {
          this.previewHtml = '<img style="width:100%;margin-top:10px;border-radius: 4px;box-sizing: border-box;" src="' + this.questionCont.xpp_detail_pic + '"/>'
        }
      } else if (this.questionCont.source_type === 4) {
        if (this.isParse) {
          this.previewHtml = '<div style="padding-top:10px;text-align:left;font-size: 16px;">解析</div>' + `<div style="padding-top: 10px; text-align:left;font-size: 16px;">${JSON.parse(this.questionCont.analysis || '{}').content}</div>` + (JSON.parse(this.questionCont.analysis || '{}').images || []).map(item => {
            return '<img style="width:100%;margin-top:10px;border-radius: 4px;box-sizing: border-box;" src="' + item + '"/>'
          }).join('')
        }
        else {
          // 线下题
          this.previewHtml = (JSON.parse(this.questionCont?.content || '{}').images || []).map(item => {
            return '<img style="width:100%;margin-top:10px;border-radius: 4px;box-sizing: border-box;" src="' + item + '"/>'
          }).join('')
        }

      }
    },
  },
};
</script>
<style lang="less">
.question-box-pdf {
  .talqs_analyze_group {
    display: block !important;
  }

  .talqs_id {
    display: none !important;
  }
}

.is-show-true {
  .talqs_analyze_group {
    display: block;
  }

  .talqs_main {
    display: none;
  }
}

.is-show-false {
  .talqs_analyze_group {
    display: none !important;
  }
}

.fail-text {
  font-size: 16px;
  margin-top: 10px;
  color: rgba(0, 0, 0, 0.9);
  text-align: left;
}
</style>