
import { ref, onMounted } from 'vue';
import questionTypes from './components/questionTypes.vue'
import { parseTime, getUrlParam } from '@/utils/index';
import { ResultList } from './types/index';
import api from './service/api';
export default {
  name: 'nodePdf',
  components: {
    questionTypes
  },
  setup () {
    const getData = ref()
    const show_answer = ref('')
    const getInitData = ()=>{
      const token = getUrlParam('token') || ''
      const question_ids = getUrlParam('question_ids') || ''
      const scope = getUrlParam('scope') || '0'
      const tal_id = getUrlParam('tal_id') || ''
      show_answer.value = getUrlParam('show_answer') || 'true'
      api.getTalTemp({error_book_ids:question_ids,scope:parseInt(scope),token:decodeURIComponent(token),tal_id:tal_id}).then((res:ResultList)=>{
        if(res.data.errcode === 0){
          if(res.data.data&&res.data.data.list&&res.data.data.list.length>0) {
            getData.value = res.data.data.list
          }else{
            window.renderdone = false
          }
        }else{
          window.renderdone = false
        }
      });
    }
    onMounted(() => {
      getInitData()
    });
    return {
      getData,
      show_answer,
      parseTime
    }
  }
}
