  <script>
  import { nextTick } from '@vue/runtime-core';
  import question from './question.vue'
  import questionSimilar from './questionSimilar.vue'
  import { getUrlParam } from '@/utils/index';
  export default {
    name: "questionTypes",
    props: ["dataVideo", "getQuestionPath", "getAllQuestionPath",'comeName',"show_answer"],
    components: {
        question,
        questionSimilar
    },
    data() {
        return {
            total:0,
            time:0,
            priceType: "member",
            previewHtml: '',
            scope:''
        };
    },
    watch: {
        dataVideo(val) {
            console.log(val, 'questionTypes');
            this.$nextTick(() => {
                window.MathJax.Hub.Queue(["Typeset", window.MathJax.Hub, this.$refs.renderQuestion], () => {
                    this.$nextTick(() => {
                        this.$nextTick(() => {
                            console.log('renderdone')
                            const loadIntervalImg = setInterval(()=>{
                                try{
                                    let flag = true
                                    document.querySelectorAll('img').forEach((img)=>{
                                        console.log(img.complete)
                                        if(!img.complete) flag = false
                                    })
                                    if(flag){
                                        window.renderdone = true
                                        clearInterval(loadIntervalImg)
                                    }
                                }catch(e){
                                    window.renderdone = true
                                    clearInterval(loadIntervalImg)
                                }
                            },100)
                        })
                    })
                });
            });
        }
    },
    methods: {
    },
    mounted(){
        this.scope = getUrlParam('scope')
        const timer = setInterval(()=>{
            if(this.time >= 55) {
                window.renderdone = true
                clearInterval(timer)
                this.time = 0
            }
            this.time++
        },1000)
    }
  };
  </script>
  
