<script>
export default {
  name: "questionSimilar",
  data () {
    return {
      previewHtml: ""
    };
  },
  props: ["questionCont", "isParse", "similarLen", "similarIndex"],
  mounted () {
    this.renderQsDom();
  },
  watch: {
    questionCont () {
      this.renderQsDom();
    }
  },
  methods: {
    renderQsDom () {
      let config = {
        analyzeVersion: 2,
        hideSource: true,
        hideDifficulty: true,
        excludeLogicToAutoLayout: [5],
        labels: {
          answer: "答案",
          analyze: "解析",
          queId: "ID",
        },
      };
      if(window.TalqsTemplate&&window.TalqsTemplate.render&&this.questionCont) this.previewHtml = window.TalqsTemplate.render(this.questionCont, config);
    },
  },
};
</script>
